questionvariables.text:
/* k1: Reduction for the blueprint (Negative Enlargement/Scale Factor < 1) */
k_red: 1/50; 

/* k2: Positive Enlargement for the final fountain sculpture */
/* The sculptor enlarges the prototype by a factor of 4 */
k_enlarge: rand(2)+2;


/* 2. Original Prototype Dimensions (The Object) */
/* A cylindrical pedestal */
r_p: 1;   /*radius*/
h_p: rand(2)+2; /*height*/  
/* 3. Calculations */
/* Blueprint dimensions (Linear) */
r_blue: float(r_p * k_red * 100); /* converted to cm */

/* Final Sculpture dimensions (Area and Volume) */
asf: k_enlarge^2;
vsf: k_enlarge^3;

vol_proto: %pi * r_p^2 * h_p;
vol_final = vol_proto * k_enlarge^3;

/* 4. Teacher Answers */
ta1: k_red;
ta2: k_enlarge;
ta3: asf;
ta4: vol_final;
